DECLARE
  s NUMBER := 0; i NUMBER := 1;
BEGIN
  LOOP
    s := s + i;
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN s > 50;
    i := i + 1;
  END LOOP;
END;

DECLARE
  v_count NUMBER := 1;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE('Iteration ' || v_count);
    v_count := v_count + 1;
    EXIT WHEN v_count > 3;
  END LOOP;
END;

DECLARE
  v_tot NUMBER := 0;
BEGIN
  FOR r IN (SELECT SAL FROM EMP) LOOP
    IF r.sal < 1500 THEN CONTINUE; END IF;
    v_tot := v_tot + r.sal;
    DBMS_OUTPUT.PUT_LINE('Processing: ' || r.sal);
    EXIT WHEN v_tot > 10000;
  END LOOP;
END;
